module sr_flip_flop (
    input wire S,
    input wire R,
    input wire reset_clk,
    output reg Q,
    output reg Qn
);
    always @(posedge reset_clk) begin
        if (S && !R) begin
            Q <= 1'b1;
            Qn <= 1'b0;
        end else if (!S && R) begin
            Q <= 1'b0;
            Qn <= 1'b1;
        end else if (S && R) begin
            // Invalid state, hold previous state
        end
        // If both S and R are low, hold the state
    end
endmodule
